input.newString:
export function processScenario(scenario: Scenario): ScenarioResult {
  return {
    results: scenario.steps.map(step => {
      if (step.op === "quote") {
        let basePremiumTotal = 0;
        const componentCounts: Record<string, number> = {};

        for (const item of step.items) {
          if (item.type === "rune" || item.type === "moonstone") {
            componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
          } else {
            basePremiumTotal += BASE_PREMIUMS[item.type] ?? 0;
          }
        }

        for (const [compType, count] of Object.entries(componentCounts)) {
          // A building block of 3 alike components is offered at a special base premium of 60 G.
          // Let's implement block premium if count === 3.
          if (count === 3) {
            basePremiumTotal += 60;
          } else {
            basePremiumTotal += count * 25;
          }
        }

        return { premium: basePremiumTotal + 5 };
      }
      return { payout: 0, remainingCap: 0 };
    })
  };
}

