export function processScenario(scenario: Scenario): ScenarioResult {
  return {
    results: scenario.steps.map(step => {
      if (step.op === "quote") {
        let basePremiumTotal = 0;
        const componentCounts: Record<string, number> = {};
        let modifierSurchargesTotal = 0;

        for (const item of step.items) {
          if (item.type === "rune" || item.type === "moonstone") {
            componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
          } else {
            const itemBase = BASE_PREMIUMS[item.type] ?? 0;
            basePremiumTotal += itemBase;
            if (item.cursed) {
              modifierSurchargesTotal += itemBase * 0.5;
            }
          }
        }

        basePremiumTotal += calculateComponentsBasePremium(componentCounts);

        // A cursed component has no distinct itemBase defined in the loop, but does a cursed component exist?
        // Let's check: "Components — for example runes and moonstones — are insured at 250 G each, with a base premium of 25 G per component."
        // And "cursed items add a 50 % risk surcharge."
        // We will make sure components also support cursed modifier.
        for (const item of step.items) {
          if (item.type === "rune" || item.type === "moonstone") {
            if (item.cursed) {
              modifierSurchargesTotal += 25 * 0.5;
            }
          }
        }

        const totalPremium = basePremiumTotal + modifierSurchargesTotal + 5;
        return { premium: Math.ceil(totalPremium) };
      }
      return { payout: 0, remainingCap: 0 };
    })
  };
}

