it("Quote: Single items with base premiums (Sword: 1000 G value, 100 G base; Amulet: 600 G value, 60 G base; Staff: 800 G value, 80 G base; Potion: 400 G value, 40 G base)", () => {
  const items = [
    { type: "sword" },
    { type: "amulet" },
    { type: "staff" },
    { type: "potion" }
  ];
  for (const item of items) {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote" as const, items: [item] }
      ]
    };
    const result = processScenario(scenario);
    let expectedBase = 0;
    if (item.type === "sword") expectedBase = 100;
    if (item.type === "amulet") expectedBase = 60;
    if (item.type === "staff") expectedBase = 80;
    if (item.type === "potion") expectedBase = 40;
    expect(result.results[0]).toEqual({ premium: expectedBase + 5 });
  }
});

input.newString:
it("Quote: Single items with base premiums (Sword: 1000 G value, 100 G base; Amulet: 600 G value, 60 G base; Staff: 800 G value, 80 G base; Potion: 400 G value, 40 G base)", () => {
  const items = [
    { type: "sword" },
    { type: "amulet" },
    { type: "staff" },
    { type: "potion" }
  ];
  for (const item of items) {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote" as const, items: [item] }
      ]
    };
    const result = processScenario(scenario);
    let expectedBase = 0;
    if (item.type === "sword") expectedBase = 100;
    if (item.type === "amulet") expectedBase = 60;
    if (item.type === "staff") expectedBase = 80;
    if (item.type === "potion") expectedBase = 40;
    // Note: By default, newcomer first insurance adds 10% surcharge (10% of base).
    // So expected premium is base + 10% base + 5 G fee = expectedBase * 1.1 + 5
    expect(result.results[0]).toEqual({ premium: expectedBase * 1.1 + 5 });
  }
});

