          } else {
            const itemBase = BASE_PREMIUMS[item.type] ?? 0;
            basePremiumTotal += itemBase;
            if (item.cursed) {
              modifierSurchargesTotal += itemBase * 0.5;
            }
            if (item.enchantment !== undefined && item.enchantment >= 5) {
              modifierSurchargesTotal += itemBase * 0.3;
            }
          }
        }

        basePremiumTotal += calculateComponentsBasePremium(componentCounts);

        for (const item of step.items) {
          if (item.type === "rune" || item.type === "moonstone") {
            if (item.cursed) {
              modifierSurchargesTotal += 25 * 0.5;
            }
            if (item.enchantment !== undefined && item.enchantment >= 5) {
              modifierSurchargesTotal += 25 * 0.3;
            }
          }
        }

        // Policy-wide modifiers
        let policyModifierPercent = 0;
        if (scenario.customer.yearsWithMHPCO >= 2) {
          policyModifierPercent -= 0.2;
        }

        // "A first insurance carries a 10 % initial assessment surcharge."
        // "each item in a quote is treated as a first insurance, regardless of customer history." -> This means +10% per item! Or is it +10% of basePremiumTotal?
        // Let's re-read: "each item in a quote is treated as a first insurance, regardless of customer history."
        // Newcomer with a cursed sword: premium 165 G.
        // Base 100 G, cursed +50 G, first insurance +10 G, fee 5 G = 165 G.
        // First insurance surcharge here is 10 G, which is 10% of the sword's base premium (100 G).
        // Since it applies to "each item in a quote", we can add 10% of base premium per item as a policy-wide modifier? Or item-specific?
        // Wait, "policy-wide modifiers (loyalty, first insurance, follow-up contract) apply to the policy base premium (the sum of all item base premiums)"
        // Since there is a first insurance surcharge for each item, does that mean first insurance surcharge = 10% * policy base premium?
        // Yes, if each item has it, 10% of each item's base premium summed up is exactly 10% of the policy base premium!
        // So policyModifierPercent += 0.1 for first insurance surcharge.
        policyModifierPercent += 0.1;

        // "Customers receive a 15 % discount on each contract after their first."
        // The steps are sequential. Later claim steps refer to policy via policy index.
        // How do we know if this is a follow-up contract?
        // "this is the customer's second quote in the scenario" -> so it depends on quoteStepsProcessed!
        // If quoteStepsProcessed > 0, then follow-up contract discount of 15% applies.
        if (quoteStepsProcessed > 0) {
