it("Claim: Deductible applies to each damaged item in a multi-item damage event (sword 500 G + amulet 300 G -> 600 G payout)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      { op: "quote" as const, items: [{ type: "sword" }, { type: "amulet" }] }, // Policy 0 (sum = 1600 G, cap = 3200 G)
      {
        op: "claim" as const,
        policy: 0,
        incident: {
          cause: "dragon",
          damages: [
            { itemType: "sword", amount: 500 },
            { itemType: "amulet", amount: 300 }
          ]
        }
      }
    ]
  };
  const result = processScenario(scenario);
  // sword: 500 - 100 = 400
  // amulet: 300 - 100 = 200
  // payout = 600
  expect(result.results[1]).toEqual({ payout: 600, remainingCap: 2600 });
});
it.todo("Claim: High enchantment (>= 8) reimbursed at 50% of damage amount (steel, enchantment 9, 1000 G damage -> 400 G payout)");

